function parseLocations(raw: string): Location[] {
  return raw
    .trim()
    .split('\n')
    .map((line) => {
      const parts = line.split(',');
      const [is_county, city_name, region_name, region_code, population_count, zipString] = parts;
      return {
        is_county: parseInt(is_county),
        city_name,
        region_name,
        region_code,
        population_count: parseInt(population_count),
        zipcodes: [...new Set(zipString.split(';').filter(Boolean))],
      };
    });
}

export const locations: Location[] = parseLocations(RAW_DATA);

/** Look up a single location by region_code + city slug */
export function getLocation(regionCode: string, citySlug: string): Location | undefined {
  return locations.find(
    (l) =>
      l.region_code.toLowerCase() === regionCode.toLowerCase() &&
      slugify(l.city_name) === citySlug.toLowerCase()
  );
}

/** Get all cities in a region */
export function getCitiesInRegion(regionCode: string): Location[] {
  return locations.filter((l) => l.region_code.toLowerCase() === regionCode.toLowerCase());
}

/** Get all unique regions */
export function getAllRegions(): { region_name: string; region_code: string }[] {
  const seen = new Set<string>();
  const result: { region_name: string; region_code: string }[] = [];
  for (const l of locations) {
    if (!seen.has(l.region_code)) {
      seen.add(l.region_code);
      result.push({ region_name: l.region_name, region_code: l.region_code });
    }
  }
  return result;
}

export function slugify(str: string): string {
  return str
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/(^-|-$)/g, '');
}
